```class Solution {
public:
    int minSwaps(vector<int>& nums) {
        int n = nums.size();
        int ones = 0, lastOne = -1;
        for (int i = 0; i < n; i++) {
            if (nums[i] == 1) {
                ones++;
                lastOne = (lastOne + 1) % n;
            }
        }
        return max(0, ones - (n - lastOne));
    }
};```
